#!/usr/bin/env bash
# migrate-skills-to-full.sh — 일회성: codex/skills 의 잔여 "소스 skill" 실디렉토리를
# codex/skills.full 로 옮기고 codex/skills/<name> 을 ../skills.full/<name> 심링크로 전환.
#
# 대상 = codex/skills/<name> 중 (실디렉토리 ∧ SKILL.md 있음 ∧ AUTO-GENERATED 아님
#        ∧ .system/. 으로 시작 안 함 ∧ 이미 심링크 아님).
# 생성 command 래퍼(AUTO-GENERATED)와 .system 은 건드리지 않는다.
#
# 기본은 DRY-RUN(변경 없음). 실제 적용은 --apply.
#
# Usage:
#   migrate-skills-to-full.sh            # dry-run: 무엇을 할지 + 충돌만 출력
#   migrate-skills-to-full.sh --apply    # 실제 이동/심링크 전환

set -euo pipefail
SSOT="${AGENT_HARNESS_BASELINE_HOME:-$HOME/.config/agent-harness-baseline}"
CUR="$SSOT/codex/skills"
FULL="$SSOT/codex/skills.full"
MARKER="AUTO-GENERATED by codex-bridge.sh"

apply=0
[[ "${1:-}" == "--apply" ]] && apply=1

[[ -d "$CUR" ]] || { echo "no $CUR" >&2; exit 1; }
mkdir -p "$FULL"

moved=0 linked=0 conflict=0 skipped=0
conflicts=()

while IFS= read -r d; do
  name="$(basename "$d")"
  # 제외: .system 등 점-디렉토리, 심링크, SKILL.md 없음, 생성 래퍼
  [[ "$name" == .* ]] && { skipped=$((skipped+1)); continue; }
  [[ -L "$d" ]] && { skipped=$((skipped+1)); continue; }
  [[ -f "$d/SKILL.md" ]] || { skipped=$((skipped+1)); continue; }
  grep -q "$MARKER" "$d/SKILL.md" && { skipped=$((skipped+1)); continue; }

  dst="$FULL/$name"
  if [[ ! -e "$dst" ]]; then
    echo "MOVE   codex/skills/$name -> skills.full/$name  (+symlink)"
    moved=$((moved+1))
    if (( apply )); then
      mv "$d" "$dst"
      ln -s "../skills.full/$name" "$d"
    fi
  elif diff -rq "$d" "$dst" >/dev/null 2>&1; then
    echo "LINK   codex/skills/$name (skills.full 동일 존재) -> symlink"
    linked=$((linked+1))
    if (( apply )); then
      rm -rf "$d"
      ln -s "../skills.full/$name" "$d"
    fi
  else
    echo "CONFLICT  codex/skills/$name ≠ skills.full/$name  (수동 판단 필요, 건너뜀)"
    conflict=$((conflict+1)); conflicts+=("$name")
  fi
done < <(find "$CUR" -mindepth 1 -maxdepth 1 -type d | sort)

echo
echo "=== 요약 ($([[ $apply == 1 ]] && echo APPLIED || echo DRY-RUN)) ==="
echo "  move:     $moved"
echo "  link:     $linked"
echo "  conflict: $conflict"
echo "  skipped:  $skipped (.system / 심링크 / 생성래퍼 / SKILL.md없음)"
if (( conflict > 0 )); then
  echo "  ⚠️ 충돌 목록 (정본 수동 결정 필요):"
  printf '     - %s\n' "${conflicts[@]}"
fi
(( apply == 0 )) && echo "  → 적용하려면: $0 --apply"
